+    // ── AlertSeverity ordering ─────────────────────────────────────────
+
+    #[test]
+    fn alert_severity_ordering(a in 0usize..4, b in 0usize..4) {
+        let sevs = [AlertSeverity::Info, AlertSeverity::Warning, AlertSeverity::Error, AlertSeverity::Critical];
+        let sa = sevs[a];
+        let sb = sevs[b];
+        if a < b {
+            prop_assert!(sa < sb);
+        } else if a > b {
+            prop_assert!(sa > sb);
+        } else {
+            prop_assert_eq!(sa, sb);
+        }
+    }
